const today = new Date().toISOString().slice(0, 10);
const stamp = Date.now();
const runId = `N8N-STOCK-NEG-${stamp}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, itemGroup: `${runId} Nhóm negative`, warehouseName: `${runId} Negative WH`, itemCode: `${runId} Negative Item`, disabledItemCode: `${runId} Disabled Item`, batchItemCode: `${runId} Batch Item`, batchId: `${runId}-BATCH-DUP`, badWarehouse: `${runId} Missing WH - TDD`, consumedSerialItem: 'N8N-STOCK-SERIAL-1779097978009 Hàng serial Đặc biệt', consumedSerialWarehouse: 'N8N-STOCK-SERIAL-1779097978009 Serial WH - TDD', consumedSerialNo: 'N8N-STOCK-SERIAL-1779097978009-SN-001', rate: 19 } }];

const read = (name) => { try { return $(name).all().map(i => i.json); } catch { return []; } };
const cases = {
  overIssue: read('Submit Over Issue'),
  wrongWarehouse: read('Create Wrong Warehouse'),
  disabledItem: read('Create Disabled Item Receipt'),
  missingWarehouse: read('Create Missing Warehouse'),
  duplicateBatch: read('Create Second Duplicate Batch'),
  serialReuse: read('Submit Serial Reuse Issue')
};
const failedAsExpected = Object.fromEntries(Object.entries(cases).map(([key, rows]) => [key, rows.some(row => row.error || row.message || row.httpCode || row.stack)]));
const text = JSON.stringify(cases);
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const status = Object.values(failedAsExpected).every(Boolean) ? 'passed' : 'failed';
return [{ json: { status, runId: $node['Build Negative Context'].json.runId, failedAsExpected, errors: Object.fromEntries(Object.entries(cases).map(([key, rows]) => [key, rows.map(row => row.error || row.message || row.httpCode || 'no error captured')])), securityFindings } }];
